import{_ as a,H as t,f as n,i}from"./chunks/framework.BHvCMIhP.js";const c=JSON.parse('{"title":"数据库分库分表","description":"","frontmatter":{},"headers":[],"relativePath":"../systemDesign/08-数据库分库分表.md","filePath":"../systemDesign/08-数据库分库分表.md","lastUpdated":1778496697000}'),e={name:"../systemDesign/08-数据库分库分表.md"};function o(r,s,l,p,d,h){return t(),n("div",null,[...s[0]||(s[0]=[i(`<h1 id="数据库分库分表" tabindex="-1">数据库分库分表 <a class="header-anchor" href="#数据库分库分表" aria-label="Permalink to &quot;数据库分库分表&quot;">​</a></h1><p>分库分表是<strong>单机 DB 撑不住后唯一的出路</strong>,但也是<strong>互联网架构里最不可逆的决策</strong>——一旦分了,后面 3 年都在还分库的债。新手最常见的错是「听说要分库」就提前分,<strong>没榨干单库就分,等于花 100 万去解决 1 万的问题</strong>。这一篇讲三件事:<strong>什么时候才该分</strong>(三条硬线)、<strong>怎么分</strong>(垂直 vs 水平 / 分片键怎么选)、<strong>分了之后最痛的三个问题怎么办</strong>(跨库查、分布式 ID、在线扩容)。</p><blockquote><p>一句话先记住:<strong>分库分表是&quot;换问题&quot;——把&quot;单机扛不住&quot;换成&quot;应用层复杂度爆炸&quot;</strong>。一旦分了,跨库 join 没了、全局排序难了、事务难了、迁移地狱来了。<strong>所有不分库就能撑过去的优化都比分库优先</strong>——加索引、归档老数据、读写分离、缓存,<strong>这些招用尽再分库</strong>。<strong>分片键选错 = 整个架构推翻重来</strong>,这是分库分表唯一不能犯的错。</p></blockquote><hr><h2 id="一、什么时候必须分-三条硬线" tabindex="-1">一、什么时候必须分?三条硬线 <a class="header-anchor" href="#一、什么时候必须分-三条硬线" aria-label="Permalink to &quot;一、什么时候必须分?三条硬线&quot;">​</a></h2><p>不要拍脑袋,<strong>用数据说话</strong>。任何一条触线,就该认真考虑分库:</p><h3 id="_1-1-数据量线-单表-5000-万行-单库-500gb" tabindex="-1">1.1 数据量线:单表 &gt; 5000 万行 / 单库 &gt; 500GB <a class="header-anchor" href="#_1-1-数据量线-单表-5000-万行-单库-500gb" aria-label="Permalink to &quot;1.1 数据量线:单表 &gt; 5000 万行 / 单库 &gt; 500GB&quot;">​</a></h3><p>MySQL 单表理论无上限,<strong>实际上 5000 万行是普遍公认的&quot;开始变慢&quot;门槛</strong>:</p><ul><li>B+ 树深度变成 4-5 层,IO 次数增加</li><li>二级索引扫描慢</li><li>DDL(改表结构)动辄几小时</li></ul><blockquote><p><strong>TiDB / PolarDB 等分布式 DB 把这条线推到 100 亿+,但它们底层仍然是分片</strong>——你只是不用自己分而已。</p></blockquote><h3 id="_1-2-qps-线-写-5000-总-50000" tabindex="-1">1.2 QPS 线:写 &gt; 5000 / 总 &gt; 50000 <a class="header-anchor" href="#_1-2-qps-线-写-5000-总-50000" aria-label="Permalink to &quot;1.2 QPS 线:写 &gt; 5000 / 总 &gt; 50000&quot;">​</a></h3><p>单 MySQL 实例(8 核 32G + SSD)的极限:</p><ul><li>读:10000-20000 QPS(走索引)</li><li>写:3000-8000 QPS(取决于事务复杂度)</li></ul><p><strong>到这条线时,先用读写分离 + 缓存挡掉读</strong>,只剩写撑不住才考虑分。</p><h3 id="_1-3-单机硬件线-32c-256gb-4tb-ssd-撑不住" tabindex="-1">1.3 单机硬件线:32C + 256GB + 4TB SSD 撑不住 <a class="header-anchor" href="#_1-3-单机硬件线-32c-256gb-4tb-ssd-撑不住" aria-label="Permalink to &quot;1.3 单机硬件线:32C + 256GB + 4TB SSD 撑不住&quot;">​</a></h3><p>这是云上单实例规格上限附近。<strong>到这一步加机器只能水平加</strong>,不能再升单机了。</p><blockquote><p>**三条线满足任一,值得考虑;满足两个,基本必分;三个都满足,<strong>今天就得分</strong>。</p></blockquote><h3 id="_1-4-反向警告-三种-假必须分-的场景" tabindex="-1">1.4 反向警告:三种&quot;假必须分&quot;的场景 <a class="header-anchor" href="#_1-4-反向警告-三种-假必须分-的场景" aria-label="Permalink to &quot;1.4 反向警告:三种&quot;假必须分&quot;的场景&quot;">​</a></h3><h4 id="场景-a-数据量-1-亿但-99-是冷数据" tabindex="-1">场景 A:数据量 1 亿但 99% 是冷数据 <a class="header-anchor" href="#场景-a-数据量-1-亿但-99-是冷数据" aria-label="Permalink to &quot;场景 A:数据量 1 亿但 99% 是冷数据&quot;">​</a></h4><p>把 5 年前的订单归档到冷库或对象存储,热库只剩 1000 万 → <strong>不用分</strong>。</p><h4 id="场景-b-qps-高但-95-是缓存能挡的" tabindex="-1">场景 B:QPS 高但 95% 是缓存能挡的 <a class="header-anchor" href="#场景-b-qps-高但-95-是缓存能挡的" aria-label="Permalink to &quot;场景 B:QPS 高但 95% 是缓存能挡的&quot;">​</a></h4><p>加 Redis 把读 QPS 降 95% → DB 实际负载小 → <strong>不用分</strong>。</p><h4 id="场景-c-单表-5000-万但只是写日志" tabindex="-1">场景 C:单表 5000 万但只是写日志 <a class="header-anchor" href="#场景-c-单表-5000-万但只是写日志" aria-label="Permalink to &quot;场景 C:单表 5000 万但只是写日志&quot;">​</a></h4><p>日志表别用 OLTP DB,直接进 Kafka → ClickHouse / ES → <strong>不用分,换技术栈</strong>。</p><hr><h2 id="二、垂直拆分-按业务模块拆库" tabindex="-1">二、垂直拆分:按业务模块拆库 <a class="header-anchor" href="#二、垂直拆分-按业务模块拆库" aria-label="Permalink to &quot;二、垂直拆分:按业务模块拆库&quot;">​</a></h2><p>最简单的一种拆分,<strong>很多人甚至不知道这叫&quot;分库&quot;</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原来:</span></span>
<span class="line"><span>  一个 mysql 库,里面有 user / order / product / comment 等所有表</span></span>
<span class="line"><span></span></span>
<span class="line"><span>垂直拆:</span></span>
<span class="line"><span>  user_db    ← user 表</span></span>
<span class="line"><span>  order_db   ← order 表、order_item 表</span></span>
<span class="line"><span>  product_db ← product 表、sku 表</span></span>
<span class="line"><span>  comment_db ← comment 表</span></span></code></pre></div><p><strong>适合</strong>:数据库还有空间,但<strong>业务模块多 + 团队拆分</strong>——每个团队一个库,互不打扰。</p><p><strong>优势</strong>:</p><ul><li>各模块独立扩展(订单写量大就单独升级 order_db 配置)</li><li>故障隔离(comment_db 挂不影响下单)</li><li>团队自治</li></ul><p><strong>代价</strong>:</p><ul><li>跨模块查询要走应用层 join(不能 SQL join 了)</li><li>跨模块事务要走分布式事务</li></ul><blockquote><p><strong>垂直拆是&quot;先于&quot;水平拆的步骤</strong>——通常先按业务垂直拆出 5-10 个库,再对单个超大业务(如 order)做水平拆。</p></blockquote><hr><h2 id="三、水平拆分-同一张表切片-分库-分表" tabindex="-1">三、水平拆分:同一张表切片(分库 + 分表) <a class="header-anchor" href="#三、水平拆分-同一张表切片-分库-分表" aria-label="Permalink to &quot;三、水平拆分:同一张表切片(分库 + 分表)&quot;">​</a></h2><p><strong>真正的&quot;分库分表&quot;</strong>——同一张表数据量太大,<strong>按某个键切成 N 份</strong>。</p><h3 id="_3-1-分库-分表-分库分表的区别" tabindex="-1">3.1 分库 / 分表 / 分库分表的区别 <a class="header-anchor" href="#_3-1-分库-分表-分库分表的区别" aria-label="Permalink to &quot;3.1 分库 / 分表 / 分库分表的区别&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原表 order(10 亿行) 在 db0 单实例里</span></span>
<span class="line"><span></span></span>
<span class="line"><span>只分表:db0 里建 order_0 ~ order_15(16 张表)</span></span>
<span class="line"><span>  → 单库 IOPS 仍是瓶颈</span></span>
<span class="line"><span></span></span>
<span class="line"><span>只分库:db0、db1、db2 三个库,每个库一张完整 order 表</span></span>
<span class="line"><span>  → 数据量没解决</span></span>
<span class="line"><span></span></span>
<span class="line"><span>分库分表:db0 ~ db15(16 个库),每个库 16 张表</span></span>
<span class="line"><span>  → 总共 16 × 16 = 256 张物理表</span></span></code></pre></div><blockquote><p><strong>生产场景几乎都是&quot;分库分表&quot;</strong>——只分表解决不了 IO 瓶颈,只分库解决不了单表变慢。</p></blockquote><h3 id="_3-2-路由方式-哈希-vs-范围-vs-时间" tabindex="-1">3.2 路由方式:哈希 vs 范围 vs 时间 <a class="header-anchor" href="#_3-2-路由方式-哈希-vs-范围-vs-时间" aria-label="Permalink to &quot;3.2 路由方式:哈希 vs 范围 vs 时间&quot;">​</a></h3><h4 id="哈希路由-最常用" tabindex="-1">哈希路由(最常用) <a class="header-anchor" href="#哈希路由-最常用" aria-label="Permalink to &quot;哈希路由(最常用)&quot;">​</a></h4><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db_index </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> hash</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(user_id) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">%</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 16</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 选哪个库</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">table_index </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> hash</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(user_id) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 16</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> %</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 16</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 选哪张表</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sql </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;SELECT * FROM order_</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">{</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">table_index</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> WHERE user_id = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">{</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">user_id</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">}</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在 db_{db_index} 上执行</span></span></code></pre></div><p><strong>优势</strong>:数据均匀分布,无热点。 <strong>劣势</strong>:扩容麻烦(从 16 库扩到 32 库,要重 hash 全部数据)。</p><h4 id="范围路由" tabindex="-1">范围路由 <a class="header-anchor" href="#范围路由" aria-label="Permalink to &quot;范围路由&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>order_id 1  ~ 1亿     → db0</span></span>
<span class="line"><span>order_id 1亿 ~ 2亿    → db1</span></span>
<span class="line"><span>order_id 2亿 ~ 3亿    → db2</span></span></code></pre></div><p><strong>优势</strong>:扩容简单(加 db3 接收新数据)。 <strong>劣势</strong>:<strong>热点严重</strong>——所有新订单都打 db_n,旧库基本没流量。</p><h4 id="时间路由" tabindex="-1">时间路由 <a class="header-anchor" href="#时间路由" aria-label="Permalink to &quot;时间路由&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2023 年订单 → db_2023</span></span>
<span class="line"><span>2024 年订单 → db_2024</span></span>
<span class="line"><span>2025 年订单 → db_2025</span></span></code></pre></div><p><strong>优势</strong>:适合日志、订单等时间序列;冷库可以用更便宜的存储。 <strong>劣势</strong>:也有热点(当年的库压力大)。</p><blockquote><p><strong>互联网业务 90% 用哈希路由</strong>——均匀压力比扩容方便更重要;<strong>日志、监控、归档场景用时间路由</strong>。<strong>范围路由只适合 ID 严格自增且历史数据访问频次和新数据接近的场景</strong>(很少)。</p></blockquote><h3 id="_3-3-分片数怎么选" tabindex="-1">3.3 分片数怎么选 <a class="header-anchor" href="#_3-3-分片数怎么选" aria-label="Permalink to &quot;3.3 分片数怎么选&quot;">​</a></h3><p><strong>选 2 的幂次方</strong>(16、32、64、128):</p><ul><li>哈希取模均匀</li><li>后期扩容时拆一变二容易</li><li>业内默认值</li></ul><p><strong>预留量</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当前数据 100 GB,3 年增长 10 倍 → 1 TB</span></span>
<span class="line"><span>单库容量目标 100 GB(留 buffer)</span></span>
<span class="line"><span>最少分 10 库,选 16 库</span></span></code></pre></div><blockquote><p><strong>常见错误</strong>:分 4 库够当下,3 年后又得扩——而扩容是地狱。<strong>宁可一开始分得多一点(16/32),也别频繁扩</strong>。<strong>淘宝订单库一开始就分 1024 个</strong>——别以为夸张,业务一爆发就庆幸。</p></blockquote><hr><h2 id="四、分片键-sharding-key-怎么选-决定生死" tabindex="-1">四、分片键(Sharding Key)怎么选:决定生死 <a class="header-anchor" href="#四、分片键-sharding-key-怎么选-决定生死" aria-label="Permalink to &quot;四、分片键(Sharding Key)怎么选:决定生死&quot;">​</a></h2><p><strong>选错分片键 = 整个架构推翻重来</strong>——这是分库分表的最大决策。</p><h3 id="_4-1-分片键的两条铁律" tabindex="-1">4.1 分片键的两条铁律 <a class="header-anchor" href="#_4-1-分片键的两条铁律" aria-label="Permalink to &quot;4.1 分片键的两条铁律&quot;">​</a></h3><p><strong>铁律 1:90% 的查询要带分片键</strong></p><p>如果分片键是 <code>user_id</code>,<strong>所有用户维度查询都很快</strong>(直接路由到一个库);<strong>但商家维度、商品维度查询要扫所有库</strong>——慢且贵。</p><p><strong>铁律 2:分片键要均匀分布</strong></p><p>用 <code>province_id</code> 当分片键 → 北上广用户多,这几个库压力大,西藏库基本空 → <strong>数据倾斜,失败</strong>。</p><h3 id="_4-2-几个典型业务的分片键选择" tabindex="-1">4.2 几个典型业务的分片键选择 <a class="header-anchor" href="#_4-2-几个典型业务的分片键选择" aria-label="Permalink to &quot;4.2 几个典型业务的分片键选择&quot;">​</a></h3><table tabindex="0"><thead><tr><th>业务</th><th>推荐分片键</th><th>原因</th></tr></thead><tbody><tr><td>订单</td><td>user_id(买家)</td><td>99% 的查询是「我的订单」</td></tr><tr><td>微博</td><td>user_id(发布者)</td><td>「某人的微博列表」最常查</td></tr><tr><td>IM 消息</td><td>conversation_id</td><td>一个会话的消息一起查</td></tr><tr><td>商品</td><td>product_id</td><td>商品详情独立查询</td></tr><tr><td>评论</td><td>target_id(被评论的资源 ID)</td><td>「某商品的评论」最常查</td></tr></tbody></table><h3 id="_4-3-多维度查询的解法-基因法-多份数据" tabindex="-1">4.3 多维度查询的解法:基因法 / 多份数据 <a class="header-anchor" href="#_4-3-多维度查询的解法-基因法-多份数据" aria-label="Permalink to &quot;4.3 多维度查询的解法:基因法 / 多份数据&quot;">​</a></h3><p><strong>问题</strong>:订单按 <code>user_id</code> 分片,但商家(seller)也要查&quot;我所有的订单&quot;——按 <code>user_id</code> 分会导致跨库扫表。</p><p><strong>解法 A:基因法(同库不同分片键)</strong></p><p>将 <code>seller_id</code> 的 hash 作为 <code>user_id</code> 生成时的&quot;基因&quot;,<strong>让同一商家的订单天然落在同一库</strong>。淘宝早期用过,<strong>复杂且强耦合,现在很少用</strong>。</p><p><strong>解法 B:存两份(空间换时间)</strong></p><p>按 <code>user_id</code> 分一份给买家查,按 <code>seller_id</code> 分一份给卖家查。两份数据通过 MQ 异步同步。<strong>主流方案</strong>——简单,代价是双倍存储。</p><p><strong>解法 C:走异构存储</strong></p><p>主表按 <code>user_id</code> 分,<strong>另起一份 ES 或 ClickHouse</strong>,所有跨维度查询走它。<strong>互联网公司默认做法</strong>——OLTP 走分库,OLAP 走列式存储。</p><blockquote><p><strong>没有&quot;完美的分片键&quot;</strong>——总有少数查询要付出代价。<strong>关键是 90/10</strong>:90% 查询走分片键直达,10% 查询走兜底方案(异构存储 / 全库扫)。</p></blockquote><hr><h2 id="五、分库后的三大痛点" tabindex="-1">五、分库后的三大痛点 <a class="header-anchor" href="#五、分库后的三大痛点" aria-label="Permalink to &quot;五、分库后的三大痛点&quot;">​</a></h2><p>分库分表的<strong>真正难度不是分,是分完之后</strong>。</p><h3 id="_5-1-痛点一-跨库-join-死掉" tabindex="-1">5.1 痛点一:跨库 join 死掉 <a class="header-anchor" href="#_5-1-痛点一-跨库-join-死掉" aria-label="Permalink to &quot;5.1 痛点一:跨库 join 死掉&quot;">​</a></h3><p><strong>问题</strong>:<code>order</code> 在 order_db,<code>user</code> 在 user_db,<strong>SQL 不能 join 了</strong>。</p><p><strong>解法</strong>:</p><h4 id="a-字段冗余" tabindex="-1">A. 字段冗余 <a class="header-anchor" href="#a-字段冗余" aria-label="Permalink to &quot;A. 字段冗余&quot;">​</a></h4><p>订单表里冗余存 <code>user_name</code> / <code>user_avatar</code>,<strong>不再 join 用户表</strong>。代价是用户改名时要更新所有订单(用 MQ 异步)。</p><h4 id="b-应用层-join" tabindex="-1">B. 应用层 join <a class="header-anchor" href="#b-应用层-join" aria-label="Permalink to &quot;B. 应用层 join&quot;">​</a></h4><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">orders </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> order_db.query(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;SELECT * FROM order WHERE user_id = 123&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">user_ids </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [o.user_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> o </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> orders]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">users </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user_db.query(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;SELECT * FROM user WHERE id IN ?&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, user_ids)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 应用层组装</span></span></code></pre></div><p>简单但慢——多了一次网络往返。</p><h4 id="c-es-异构" tabindex="-1">C. ES 异构 <a class="header-anchor" href="#c-es-异构" aria-label="Permalink to &quot;C. ES 异构&quot;">​</a></h4><p>把 join 后的&quot;宽表&quot;提前算好存到 ES。复杂查询走 ES。</p><h3 id="_5-2-痛点二-跨分片排序-分页" tabindex="-1">5.2 痛点二:跨分片排序 / 分页 <a class="header-anchor" href="#_5-2-痛点二-跨分片排序-分页" aria-label="Permalink to &quot;5.2 痛点二:跨分片排序 / 分页&quot;">​</a></h3><p><strong>问题</strong>:查&quot;全平台最新 100 个订单&quot;,数据散在 16 个库。</p><p><strong>朴素解法(几乎所有人第一次想的)</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每个库查最新 100 → 总共 1600 条 → 应用层排序取前 100</span></span></code></pre></div><p><strong>问题</strong>:</p><ul><li>16 个库各查 100 条,<strong>网络开销大</strong></li><li><strong>深分页惨烈</strong>:查第 100 页(skip 9900),要从每个库取 10000 条,网络爆炸</li></ul><p><strong>正确解法</strong>:</p><h4 id="a-用单独的-es-clickhouse" tabindex="-1">A. 用单独的 ES / ClickHouse <a class="header-anchor" href="#a-用单独的-es-clickhouse" aria-label="Permalink to &quot;A. 用单独的 ES / ClickHouse&quot;">​</a></h4><p>复杂排序、聚合、分页全部走异构存储。<strong>主流互联网做法</strong>。</p><h4 id="b-业务限制深分页" tabindex="-1">B. 业务限制深分页 <a class="header-anchor" href="#b-业务限制深分页" aria-label="Permalink to &quot;B. 业务限制深分页&quot;">​</a></h4><p>订单列表只允许查前 100 页,翻不到 1000 页。<strong>淘宝 / 京东都这么做</strong>——你试试翻它们订单列表第 1000 页,根本翻不动。</p><h4 id="c-游标分页代替-offset-分页" tabindex="-1">C. 游标分页代替 offset 分页 <a class="header-anchor" href="#c-游标分页代替-offset-分页" aria-label="Permalink to &quot;C. 游标分页代替 offset 分页&quot;">​</a></h4><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 错:SELECT * FROM order ORDER BY id DESC LIMIT 9900, 100</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 对:SELECT * FROM order WHERE id &lt; ? ORDER BY id DESC LIMIT 100</span></span></code></pre></div><p>游标分页<strong>不能跳页,但能无限翻</strong>——<strong>移动端无限滚动的标准做法</strong>。</p><h3 id="_5-3-痛点三-分布式事务" tabindex="-1">5.3 痛点三:分布式事务 <a class="header-anchor" href="#_5-3-痛点三-分布式事务" aria-label="Permalink to &quot;5.3 痛点三:分布式事务&quot;">​</a></h3><p><strong>问题</strong>:下单 = <code>order_db</code> 插订单 + <code>inventory_db</code> 扣库存,跨库,<strong>MySQL 本地事务不管用</strong>。</p><p><strong>解法见 23 篇订单与支付,这里只列方案选择</strong>:</p><ul><li><strong>强一致</strong>:2PC / XA(慢,性能差,几乎不用)</li><li><strong>最终一致</strong>:Saga / 本地消息表 / TCC(主流)</li><li><strong>最简单</strong>:同库时就别跨库,关联表都放同一分片下</li></ul><hr><h2 id="六、分布式-id-生成" tabindex="-1">六、分布式 ID 生成 <a class="header-anchor" href="#六、分布式-id-生成" aria-label="Permalink to &quot;六、分布式 ID 生成&quot;">​</a></h2><p>分库后,<strong>自增 ID 失效</strong>——不同库的 <code>id</code> 会重复。需要全局唯一 ID。</p><h3 id="_6-1-几种方案对比" tabindex="-1">6.1 几种方案对比 <a class="header-anchor" href="#_6-1-几种方案对比" aria-label="Permalink to &quot;6.1 几种方案对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方案</th><th>优点</th><th>缺点</th></tr></thead><tbody><tr><td>UUID</td><td>简单,纯本地生成</td><td>36 字节,无序,索引性能差</td></tr><tr><td>数据库自增</td><td>严格有序</td><td>单点,QPS 上限低</td></tr><tr><td>号段模式</td><td>高性能,有序</td><td>重启可能浪费一段号</td></tr><tr><td>雪花算法(Snowflake)</td><td>64 位,有序,高性能</td><td>时钟回拨问题</td></tr><tr><td>Redis INCR</td><td>高性能,有序</td><td>依赖 Redis 高可用</td></tr><tr><td>TiDB / PolarDB 自带</td><td>业务无感</td><td>绑定 DB</td></tr></tbody></table><h3 id="_6-2-雪花算法-snowflake-详解" tabindex="-1">6.2 雪花算法(Snowflake)详解 <a class="header-anchor" href="#_6-2-雪花算法-snowflake-详解" aria-label="Permalink to &quot;6.2 雪花算法(Snowflake)详解&quot;">​</a></h3><p>最流行的方案,Twitter 开源:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>64 位:</span></span>
<span class="line"><span>  1 位符号(永远 0)</span></span>
<span class="line"><span>  41 位时间戳(毫秒)        → 69 年</span></span>
<span class="line"><span>  10 位机器 ID(workerId)   → 1024 台机器</span></span>
<span class="line"><span>  12 位序列号               → 单机每毫秒 4096 个 ID</span></span>
<span class="line"><span></span></span>
<span class="line"><span>例:1234567890_1234567890_512_42</span></span></code></pre></div><p><strong>优势</strong>:有序(便于索引)、纯本地生成、QPS 极高。</p><p><strong>坑</strong>:</p><ul><li><strong>时钟回拨</strong>:NTP 校时时机器时间倒退,可能生成重复 ID <ul><li>对策:发现回拨就拒绝服务 / 等待</li></ul></li><li><strong>机器 ID 分配</strong>:1024 个机器 ID 怎么分? <ul><li>对策:启动时去 ZooKeeper / 配置中心抢一个</li></ul></li></ul><h3 id="_6-3-号段模式-美团-leaf" tabindex="-1">6.3 号段模式(美团 Leaf) <a class="header-anchor" href="#_6-3-号段模式-美团-leaf" aria-label="Permalink to &quot;6.3 号段模式(美团 Leaf)&quot;">​</a></h3><p>每次从 DB 取一段 ID 区间(比如 1000-2000),发完了再取下一段:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>应用本地缓存 [1000, 2000) 这一段 ID</span></span>
<span class="line"><span>本地用完 → 一次性向 DB 申请 [2000, 3000)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>DB 只更新一次&quot;已发到 3000&quot;,压力小</span></span>
<span class="line"><span>应用本地发 ID,极快</span></span></code></pre></div><p><strong>优势</strong>:有序、性能高、依赖少。 <strong>缺点</strong>:重启时浪费一段(没用完的 ID 丢弃)。</p><blockquote><p><strong>生产场景多用雪花或号段</strong>——UUID 只用在不需要排序的场景(文件名、临时 token)。</p></blockquote><hr><h2 id="七、在线扩容-从-16-库到-32-库" tabindex="-1">七、在线扩容:从 16 库到 32 库 <a class="header-anchor" href="#七、在线扩容-从-16-库到-32-库" aria-label="Permalink to &quot;七、在线扩容:从 16 库到 32 库&quot;">​</a></h2><p><strong>最痛的运维操作</strong>——客户在线,数据要重新分布。</p><h3 id="_7-1-朴素方案-不可用" tabindex="-1">7.1 朴素方案(不可用) <a class="header-anchor" href="#_7-1-朴素方案-不可用" aria-label="Permalink to &quot;7.1 朴素方案(不可用)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 停服务</span></span>
<span class="line"><span>2. 把每条数据按新规则 (hash % 32) 重算路由</span></span>
<span class="line"><span>3. 移到新库</span></span>
<span class="line"><span>4. 启服务</span></span></code></pre></div><p><strong>死路一条</strong>:数据 TB 级,迁移要几天,<strong>没人能停服务这么久</strong>。</p><h3 id="_7-2-主流方案-双写-数据同步" tabindex="-1">7.2 主流方案:双写 + 数据同步 <a class="header-anchor" href="#_7-2-主流方案-双写-数据同步" aria-label="Permalink to &quot;7.2 主流方案:双写 + 数据同步&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 32 库准备好(新增 16 库)</span></span>
<span class="line"><span>2. 应用层&quot;双写&quot;:写入按 mod 16 写老库,同时按 mod 32 写新库</span></span>
<span class="line"><span>3. 后台任务把老库存量数据按 mod 32 同步到新库</span></span>
<span class="line"><span>4. 同步完成后切流量到新库</span></span>
<span class="line"><span>5. 老库下线</span></span></code></pre></div><p><strong>关键技巧</strong>:</p><ul><li>双写阶段保证幂等(同一数据写老库写新库)</li><li>同步用 binlog(Canal / DTS)实时跟进增量</li><li>切流时灰度(1% → 10% → 50% → 100%)</li></ul><h3 id="_7-3-终极优化-成倍扩容" tabindex="-1">7.3 终极优化:成倍扩容 <a class="header-anchor" href="#_7-3-终极优化-成倍扩容" aria-label="Permalink to &quot;7.3 终极优化:成倍扩容&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原 16 库:db0 ~ db15</span></span>
<span class="line"><span>扩到 32 库:db0a / db0b / db1a / db1b / ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>数据迁移规则:</span></span>
<span class="line"><span>  db0 的数据,user_id % 32 == 0 留 db0a,== 16 移 db0b</span></span>
<span class="line"><span>  → 每个老库只迁一半数据,迁出去到新库</span></span></code></pre></div><p><strong>优势</strong>:每条数据<strong>只可能在两个库之间二选一</strong>,迁移路径明确,中途出错容易补。</p><blockquote><p><strong>成倍扩容是分库分表设计阶段就应该规划好的</strong>——所以分片数选 2 的幂(16 → 32 → 64),不要选 10 → 20 这种。</p></blockquote><hr><h2 id="八、shardingsphere-vitess-mycat-分库中间件" tabindex="-1">八、ShardingSphere / Vitess / MyCat:分库中间件 <a class="header-anchor" href="#八、shardingsphere-vitess-mycat-分库中间件" aria-label="Permalink to &quot;八、ShardingSphere / Vitess / MyCat:分库中间件&quot;">​</a></h2><p>不要自己手写分库路由——<strong>用成熟的中间件</strong>:</p><table tabindex="0"><thead><tr><th>中间件</th><th>来源</th><th>特点</th></tr></thead><tbody><tr><td>ShardingSphere</td><td>Apache</td><td>Java 生态最流行,功能全</td></tr><tr><td>Vitess</td><td>YouTube → CNCF</td><td>K8s 原生,Go 语言,大规模实战</td></tr><tr><td>MyCat</td><td>国产</td><td>老牌,但社区活跃度下降</td></tr><tr><td>ProxySQL</td><td>MySQL</td><td>偏读写分离,分片功能弱</td></tr></tbody></table><h3 id="_8-1-两种部署模式" tabindex="-1">8.1 两种部署模式 <a class="header-anchor" href="#_8-1-两种部署模式" aria-label="Permalink to &quot;8.1 两种部署模式&quot;">​</a></h3><p><strong>Sidecar 模式(JDBC 层)</strong>:库直连 MySQL,中间件作为 JDBC Driver,客户端无感。<strong>性能高,运维简单</strong>。</p><p><strong>Proxy 模式</strong>:中间件作为独立服务(类似 MySQL),应用连中间件。<strong>多语言友好,但多了一跳延迟</strong>。</p><blockquote><p>Java 项目优先用 ShardingSphere JDBC;<strong>多语言项目用 ShardingSphere Proxy 或 Vitess</strong>。</p></blockquote><hr><h2 id="九、什么情况下不分库-newsql-和-htap" tabindex="-1">九、什么情况下不分库:NewSQL 和 HTAP <a class="header-anchor" href="#九、什么情况下不分库-newsql-和-htap" aria-label="Permalink to &quot;九、什么情况下不分库:NewSQL 和 HTAP&quot;">​</a></h2><p><strong>云原生 NewSQL</strong> 让你&quot;不分库的分库&quot;:</p><table tabindex="0"><thead><tr><th>DB</th><th>特点</th></tr></thead><tbody><tr><td>TiDB</td><td>兼容 MySQL,自动分片,跨地域强一致</td></tr><tr><td>PolarDB</td><td>阿里云,兼容 MySQL,共享存储 + 多读节点</td></tr><tr><td>CockroachDB</td><td>Spanner 风格,全球强一致</td></tr><tr><td>OceanBase</td><td>蚂蚁,多活 + 高并发</td></tr></tbody></table><p><strong>优势</strong>:对应用透明,SQL 还是普通 SQL,不用关心分片。 <strong>代价</strong>:复杂度藏在数据库里,运维仍需要专业 DBA;<strong>成本通常比 MySQL 高几倍</strong>。</p><blockquote><p><strong>新业务可以直接选 TiDB</strong>——避免分库分表的所有痛苦,<strong>但要做好成本和团队学习曲线的预算</strong>。<strong>老业务从 MySQL 迁 TiDB 也是大工程</strong>,不是想迁就能迁。</p></blockquote><hr><h2 id="十、踩坑提醒" tabindex="-1">十、踩坑提醒 <a class="header-anchor" href="#十、踩坑提醒" aria-label="Permalink to &quot;十、踩坑提醒&quot;">​</a></h2><ol><li><strong>过早分库</strong>——单库还能撑,提前分库纯找罪受</li><li><strong>不归档冷数据就分库</strong>——5 年前的订单归档了 80% 数据消失,根本不用分</li><li><strong>分片键选错</strong>——业务跑半年后想换,基本等于重做</li><li><strong>分片键不均匀</strong>——按地区分,北上广撑爆,西藏空闲</li><li><strong>分太少</strong>——半年后又扩,扩容是地狱</li><li><strong>不留扩容余地</strong>——分 10 库不是 2 的幂次,扩到 20 麻烦</li><li><strong>跨库事务用 2PC</strong>——性能极差,生产几乎不用</li><li><strong>跨库 join 用 MyCat 自动 join</strong>——慢且不稳定,自己应用层 join 或走 ES</li><li><strong>深分页用 offset</strong>——10 万行后死掉,必须改游标分页</li><li><strong>不用中间件自己手写路由</strong>——bug 写不完,后期维护噩梦</li><li><strong>分布式 ID 用 UUID</strong>——索引性能崩溃,选雪花或号段</li><li><strong>没考虑数据迁移</strong>——分库容易,后期重新分片(rebalance)是地狱</li></ol><hr><p>下一篇:<code>09-读写分离与复制.md</code>,讲主从复制三种模式(异步 / 半同步 / 同步)的取舍,主从延迟为什么是「读自己写」的天敌,从库延迟监控怎么做,以及多主复制为什么大多数场景下不该用——除非你是 Google Spanner 级别。</p>`,156)])])}const u=a(e,[["render",o]]);export{c as __pageData,u as default};
